import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';

function Dashboard() {
  const [user, setUser] = useState(null);
  const [skills, setSkills] = useState(""); 
  const [isLoading, setIsLoading] = useState(false);
  const navigate = useNavigate();

  // १. लॉगिन असलेल्या युजरचा डेटा लोड करणे
  useEffect(() => {
    const loggedInUser = localStorage.getItem('user');
    if (loggedInUser) {
      const parsedUser = JSON.parse(loggedInUser);
      setUser(parsedUser);
      setSkills(parsedUser.skills || ""); // आधीचे स्किल्स लोड करा
    } else {
      navigate('/login'); // लॉगिन नसेल तर बाहेर पाठवा
    }
  }, [navigate]);

  // २. स्किल्स अपडेट करण्याचे लॉजिक (दुरुस्त केलेले)
  const handleUpdateSkills = async (e) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      const response = await fetch('http://localhost:3000/api/update-profile', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ 
          email: user.email, 
          skills: skills 
        }),
      });

      const data = await response.json();

      if (response.ok) {
        alert("✅ Profile Updated Successfully!");
        // LocalStorage आणि State मध्ये नवीन डेटा अपडेट करा
        const updatedUser = { ...user, skills: data.user.skills };
        localStorage.setItem('user', JSON.stringify(updatedUser));
        setUser(updatedUser);
      } else {
        alert("❌ Update Failed: " + data.msg);
      }
    } catch (error) {
      alert("⚠️ Server Connection Error. Please check your backend.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate('/login');
  };

  if (!user) return <h2 style={{ textAlign: 'center', marginTop: '50px' }}>Loading Dashboard...</h2>;

  return (
    <div style={{ padding: '40px', maxWidth: '900px', margin: '0 auto', fontFamily: 'Poppins, sans-serif' }}>
      
      {/* Header Section */}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' }}>
        <h1 style={{ color: '#1e293b', margin: 0 }}>Welcome, {user.fullName}! 👋</h1>
        <button onClick={handleLogout} style={{ padding: '10px 20px', background: '#fee2e2', color: '#ef4444', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold' }}>
          Logout
        </button>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '30px' }}>
        
        {/* Left Side: User Info Card */}
        <div style={{ background: 'white', padding: '25px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
          <h3 style={{ borderBottom: '2px solid #f1f5f9', paddingBottom: '10px' }}>Personal Info</h3>
          <p><strong>Username:</strong> {user.username}</p>
          <p><strong>Email:</strong> {user.email}</p>
          <p><strong>Role:</strong> <span style={{ color: '#38bdf8', fontWeight: 'bold' }}>{user.role}</span></p>
          <p><strong>Status:</strong> <span style={{ color: '#10b981' }}>● Active</span></p>
        </div>

        {/* Right Side: Skills Update Form */}
        <div style={{ background: 'white', padding: '25px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9' }}>
          <h3 style={{ marginBottom: '20px' }}>Manage Your Profile</h3>
          
          <form onSubmit={handleUpdateSkills}>
            <div style={{ marginBottom: '15px' }}>
              <label style={{ display: 'block', marginBottom: '8px', fontWeight: '600', color: '#475569' }}>Your Skills</label>
              <textarea 
                value={skills} 
                onChange={(e) => setSkills(e.target.value)} 
                placeholder="उदा. React, Node.js, Graphic Design..." 
                style={{ 
                  width: '100%', 
                  padding: '15px', 
                  borderRadius: '12px', 
                  border: '1px solid #cbd5e1', 
                  minHeight: '120px', 
                  fontSize: '15px',
                  boxSizing: 'border-box'
                }}
              />
            </div>
            
            <button 
              type="submit" 
              disabled={isLoading}
              style={{ 
                width: '100%', 
                padding: '14px', 
                background: '#1e293b', 
                color: 'white', 
                border: 'none', 
                borderRadius: '12px', 
                cursor: 'pointer', 
                fontWeight: 'bold',
                transition: '0.3s'
              }}
            >
              {isLoading ? "Saving..." : "Save Changes"}
            </button>
          </form>
        </div>

      </div>

      {/* Dashboard Footer/Stats (Optional) */}
      <div style={{ marginTop: '40px', textAlign: 'center', color: '#94a3b8' }}>
        <p>Student Freelancer Marketplace © 2024</p>
      </div>
    </div>
  );
}

export default Dashboard;
